  function shipmentDoc(o,breakAfter=false){ const sub=total(o), freight=Number(o.shippingFee||o.freight||0), discount=Number(o.discount||0), grand=sub+freight-discount; return `<section class="proPrintDoc ${breakAfter?'pageBreak':''}"><div class="proPrintTop"><div><h1>${txt(S.settings.name||'MoriFlow')}｜出貨單</h1><small>${txt(S.settings.slogan||'')}</small></div><div class="printMeta"><b>列印時間</b><br>${new Date().toLocaleString('zh-TW')}<br><b>建立時間</b><br>${txt(o.created||o.date||'')}</div></div><table class="proInfo"><tr><th>訂單編號</th><td>${txt(o.id)}</td><th>訂單日期</th><td>${txt(String(o.created||o.date||'').slice(0,10))}</td><th>訂單類型</th><td>${txt(o.type||'一般訂單')}</td></tr><tr><th>會員編號</th><td>${txt(o.memberNo||'-')}</td><th>會員姓名</th><td>${txt(o.member||'-')}</td><th>會員電話</th><td>${txt(o.phone||'-')}</td></tr><tr><th>寄送方式</th><td colspan="2">${txt(o.shipping||'-')}</td><th>付款方式</th><td colspan="2">${txt(o.payment||'-')}</td></tr><tr><th>寄送地址/超商門市</th><td colspan="5">${txt(o.address||'-')}</td></tr></table><h2>商品明細</h2><table class="proItems"><thead><tr><th>商品編號</th><th>商品名稱</th><th>商品規格</th><th>單價</th><th>數量</th><th>金額</th></tr></thead><tbody>${(o.items||[]).map(i=>`<tr><td>${txt(i.pid||i.sku||'')}</td><td>${txt(i.name||'')}</td><td>${txt(i.spec||i.variant||'')}</td><td>${money(i.price)}</td><td>${i.qty||1}</td><td>${money(Number(i.price||0)*Number(i.qty||1))}</td></tr>`).join('')}</tbody></table><table class="proTotals"><tr><th>小計</th><td>${money(sub)}</td></tr><tr><th>運費</th><td>${money(freight)}</td></tr><tr><th>折扣</th><td>${money(discount)}</td></tr><tr class="grand"><th>總計</th><td>${money(grand)}</td></tr></table><div class="proNote"><b>訂單備註</b><br>${txt(o.note||o.exportNote||o.printNotice||'無')}</div></section>`; }
