    S.cart=S.cart||[];
    S.cart.push({id:p.id,name:p.name,price:Number(v?.price||p.price||0),cost:Number(v?.cost||p.cost||0),qty,variant:v?.name||Object.values(p.variants||{}).filter(Boolean).join(' / ')||'基本款',sku:v?.sku||p.sku});
